// ── Baseline limits (2026) ─────────────────────────────────────────────────
export const BASELINE_CONFORMING = { '2unit': 1066250, '3unit': 1288800, '4unit': 1601750 };
export const BASELINE_FHA        = { '2unit': 693050,  '3unit': 837700,  '4unit': 1041125 };

/**
 * getLimitsForZip(zip5, numUnits)
 * Returns { conforming, fha } loan limits for the given ZIP and unit count.
 * Falls back to baseline if ZIP is not in a high-cost county.
 *
 * @param {string} zip5 - 5-digit ZIP code (e.g. "90210")
 * @param {2|3|4}  numUnits
 * @returns {{ conforming: number, fha: number, county: string|null, state: string|null, isHighCost: boolean }}
 */
export function getLimitsForZip(zip5, numUnits) {
  const unitKey = `${numUnits}unit`;
  const fips = ZIP_TO_FIPS[zip5];
  if (!fips) {
    return {
      conforming: BASELINE_CONFORMING[unitKey],
      fha:        BASELINE_FHA[unitKey],
      county:     null,
      state:      null,
      isHighCost: false,
    };
  }
  const c = COUNTY_LIMITS[fips];
  if (!c) {
    return {
      conforming: BASELINE_CONFORMING[unitKey],
      fha:        BASELINE_FHA[unitKey],
      county:     null,
      state:      null,
      isHighCost: false,
    };
  }
  // c = [name, state, c2, c3, c4, f2, f3, f4]
  const idx = numUnits - 2; // 2→0, 3→1, 4→2
  return {
    conforming: c[2 + idx],
    fha:        c[5 + idx],
    county:     c[0],
    state:      c[1],
    isHighCost: true,
  };
}

/**
 * extractZip(address)
 * Extracts a 5-digit ZIP from a deal address string.
 * Returns null if no ZIP found.
 */
export function extractZip(address) {
  if (!address) return null;
  const m = address.match(/\b(\d{5})\b/);
  return m ? m[1] : null;
}
